function parentMessagingModule() {
  // Parents can only communicate with teachers of their children's classes
  // Get parent's children classes
  const wardTeacherIds = new Set();
  
  // For this demo, assume parent has children in JHS 1 and Basic 3
  const childrenClasses = ['JHS 1', 'Basic 3'];
  
  // Find all teachers for these classes
  childrenClasses.forEach(className => {
    const classInfo = classesData.find(c => c.name === className);
    if (classInfo) {
      wardTeacherIds.add(classInfo.teacher_id);
    }
  });
  
  // Get ward's teachers and create contact info
  const wardTeachers = teachersData.filter(t => wardTeacherIds.has(t.teacher_id));
  
  const conversations = {};
  wardTeachers.forEach(t => {
    conversations[t.name] = {
      name: t.name,
      info: { name: t.name, role: 'Teacher', avatar: t.avatar_color, status: 'Offline' },
      lastMsg: 'Click to message ' + t.name,
      time: 'Just now'
    };
  });

  if (!currentChat || !wardTeachers.find(t => t.name === currentChat)) {
    currentChat = wardTeachers.length > 0 ? wardTeachers[0].name : null;
  }

  let chatMessages = [];
  if (currentChat) {
    chatMessages = allMessages.filter(m =>
      (m.sender === 'Parent Serwaa' && m.recipient === currentChat) ||
      (m.sender === currentChat && m.recipient === 'Parent Serwaa')
    ).sort((a, b) => a.id - b.id);
  }

  const conversationsList = Object.entries(conversations).map(([name, conv]) => {
    const isActive = name === currentChat;
    const teacher = wardTeachers.find(t => t.name === name);
    const className = teacher ? teacher.class_assigned : 'N/A';
    const unread = getUnreadCount('Parent Serwaa', name);
    
    return `
      <div class="sb-item" style="padding:10px 8px;border-radius:10px;cursor:pointer;background:${isActive ? 'var(--blue-main)' : 'transparent'};margin-bottom:3px" 
           onclick="currentChat='${name}';renderMain()">
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:3px">
          <div class="av av-sm av-${conv.info.avatar}"></div>
          <div style="flex:1">
            <span style="font-size:12px;color:${isActive ? 'white' : 'var(--gray-700)'}">${name}${unread?` <span class="badge b-danger" style="font-size:10px;margin-left:6px">${unread}</span>`:''}</span>
            <div style="font-size:9px;color:${isActive ? 'rgba(255,255,255,.7)' : 'var(--gray-500)'}">${className} Teacher</div>
          </div>
        </div>
      </div>
    `;
  }).join('');

  const currentContact = wardTeachers.find(t => t.name === currentChat);
  const currentContactInfo = currentContact ? { avatar: currentContact.avatar_color, name: currentContact.name } : { avatar: 'blue', name: 'Teacher' };
  
  const messagesHTML = chatMessages.map(msg => {
    const isSender = msg.sender === 'Parent Serwaa';
    return `
      <div class="chat-msg${isSender ? ' me' : ''}">
        <div class="av av-sm av-${isSender ? 'gold' : currentContactInfo.avatar}"></div>
        <div>
          <div class="chat-bubble${isSender ? ' me-bubble' : ' them'}">${msg.text}</div>
          <div class="chat-meta${isSender ? ' me' : ''}" style="${isSender ? 'text-align:right' : ''}">
            ${isSender ? 'You' : msg.sender} · ${msg.time}
          </div>
        </div>
      </div>
    `;
  }).join('');

  const infoMsg = wardTeachers.length === 0 ? `<div style="padding:20px;text-align:center;background:var(--warning-light);border-radius:8px;color:var(--gold-dark)"><i class="fas fa-info-circle"></i> You can only message teachers of your children's classes.</div>` : '';

  return hdr('Messages', 'Communicate with your children\'s teachers', 'Messages') + `
    <div style="display:flex;gap:14px;height:calc(100vh - 300px)">
      <div style="width:280px;border:1px solid var(--gray-200);border-radius:8px;overflow-y:auto;background:var(--gray-xpale)">
        <div style="padding:12px;border-bottom:1px solid var(--gray-200);font-weight:700;color:var(--blue-dark)">Teachers (${wardTeachers.length})</div>
        ${conversationsList || '<div style="padding:20px;text-align:center;color:var(--gray-400);font-size:12px">No conversations</div>'}
      </div>
      <div style="flex:1;display:flex;flex-direction:column;border:1px solid var(--gray-200);border-radius:8px;background:white">
        <div style="padding:14px;border-bottom:1px solid var(--gray-200);display:flex;align-items:center;justify-content:space-between">
          <div>
            <div style="font-weight:700;color:var(--blue-dark)">${currentContact ? currentContact.name : 'Select a teacher'}</div>
            <div style="font-size:11px;color:var(--gray-500)">${currentContact ? currentContact.subject : 'Choose a teacher to message'}</div>
          </div>
          ${currentContact ? `<button class="btn btn-secondary btn-sm" onclick="startVoiceCall('${String(currentContact.name).replace(/'/g, "\\'")}')"><i class="fas fa-phone"></i> Call</button>` : ''}
        </div>
        ${infoMsg}
        <div style="flex:1;overflow-y:auto;padding:14px;display:flex;flex-direction:column;gap:8px">
          ${messagesHTML || '<div style="text-align:center;color:var(--gray-400);padding:40px;font-size:12px">No messages yet. Start a conversation!</div>'}
        </div>
        ${currentContact ? `
        <div style="padding:12px;border-top:1px solid var(--gray-200);display:flex;gap:8px">
          <input type="text" id="msg-input" placeholder="Type your message..." style="flex:1;padding:8px 10px;border:1px solid var(--gray-300);border-radius:4px;font-size:12px" onkeypress="if(event.key==='Enter') sendMessage('${currentContact.name}')">
          <button class="btn btn-primary btn-sm" onclick="sendMessage('${currentContact.name}')"><i class="fas fa-paper-plane"></i> Send</button>
        </div>` : ''}
      </div>
    </div>`;
}

function sendMessage(recipient) {
  const input = document.getElementById('msg-input');
  const text = input ? input.value.trim() : '';
  
  if (!text) {
    showToast('Please type a message', 'warning');
    return;
  }

  // Add message to allMessages
  const newId = Math.max(...allMessages.map(m => m.id || 0), 0) + 1;
  allMessages.push({
    id: newId,
    sender: 'Parent Serwaa',
    recipient: recipient,
    text: text,
    time: new Date().toLocaleTimeString('en-US', {hour: '2-digit', minute:'2-digit'})
  });

  if (input) input.value = '';
  renderMain();
  showToast('<i class="fas fa-check-circle"></i> Message sent!', 'success');
}


function filterNotices() {
  const searchTerm = (document.getElementById('notice-search')?.value || '').toLowerCase();
  const noticeItems = document.querySelectorAll('.notice-item');

  noticeItems.forEach(item => {
    const title = item.dataset.title || '';
    const audience = item.dataset.audience || '';
    const activeFilter = document.querySelector('.filter-btn.active');
    const audienceFilter = activeFilter ? activeFilter.dataset.audience : 'All';

    const matchesSearch = title.includes(searchTerm);
    const matchesAudience = audienceFilter === 'All' || audience === audienceFilter;

    item.style.display = matchesSearch && matchesAudience ? 'block' : 'none';
  });
}

function filterByAudience(audience) {
  // Update active button
  document.querySelectorAll('.filter-btn').forEach(btn => btn.classList.remove('active'));
  const activeBtn = document.querySelector(`.filter-btn[data-audience="${audience}"]`);
  if (activeBtn) activeBtn.classList.add('active');
  filterNotices();
}

async function publishNotice(event) {
  event.preventDefault();

  const title    = document.getElementById('notice-title').value.trim();
  const audience = document.getElementById('notice-audience').value;
  const priority = document.getElementById('notice-priority').value;
  const message  = document.getElementById('notice-message').value.trim();

  if (!title || !message) {
    showToast('<i class="fas fa-times-circle"></i> Please fill all required fields', 'error');
    return;
  }

  const btn = event.target.querySelector('[type=submit]') || event.target.querySelector('.btn-primary');
  if (btn) { btn.disabled = true; btn.textContent = 'Publishing...'; }

  const res = await API.notices.create({ title, audience, priority, message,
    posted_by: currentRole, notice_date: new Date().toISOString().split('T')[0] });

  if (btn) { btn.disabled = false; btn.textContent = 'Publish Notice'; }

  if (!res || !res.success) {
    showToast('<i class="fas fa-times-circle"></i> ' + (res?.message || 'Failed to publish'), 'error');
    return;
  }

  event.target.reset();
  showToast(`<i class="fas fa-check-circle"></i> Notice "${title}" published!`, 'success');
  setTimeout(() => renderMain(), 1200);
}

function draftNotice() {
  const title = document.getElementById('notice-title').value;

  if (!title) {
    showToast('<i class="fas fa-times-circle"></i> Please enter a title for your draft', 'error');
    return;
  }

  showToast(`<i class="fas fa-file-alt"></i> Draft "${title}" saved to your account`, 'info');
  document.querySelector('form[onsubmit="publishNotice(event)"]').reset();
}

function editNotice(noticeId) {
  const notice = NOTICES_DATA.find(n => n.id === noticeId);
  if (!notice) {
    showToast('<i class="fas fa-times-circle"></i> Notice not found', 'error');
    return;
  }

  const formHTML = `
    <div style="max-width:850px;background:white;border-radius:12px;overflow:hidden">
      <div style="padding:20px;background:var(--blue-main);color:white">
        <h2 style="margin:0">Edit Notice</h2>
        <p style="margin:8px 0 0 0;font-size:13px;opacity:0.9">${notice.title}</p>
      </div>
      
      <form onsubmit="saveEditNotice(event, ${noticeId})" style="padding:20px">
        <div class="f-field" style="margin-bottom:12px">
          <label>Notice Title</label>
          <input type="text" id="edit-notice-title" value="${notice.title}" required>
        </div>
        
        <div class="f-field" style="margin-bottom:12px">
          <label>Target Audience</label>
          <select id="edit-notice-audience" required>
            <option value="All" ${notice.audience === 'All' ? 'selected' : ''}>All</option>
            <option value="Students" ${notice.audience === 'Students' ? 'selected' : ''}>Students</option>
            <option value="Staff" ${notice.audience === 'Staff' ? 'selected' : ''}>Staff</option>
            <option value="Teachers" ${notice.audience === 'Teachers' ? 'selected' : ''}>Teachers</option>
            <option value="Parents" ${notice.audience === 'Parents' ? 'selected' : ''}>Parents</option>
            <option value="Form 3" ${notice.audience === 'Form 3' ? 'selected' : ''}>Form 3 Only</option>
          </select>
        </div>
        
        <div class="f-field" style="margin-bottom:12px">
          <label>Priority</label>
          <select id="edit-notice-priority" required>
            <option value="Normal" ${notice.priority === 'Normal' ? 'selected' : ''}>Normal</option>
            <option value="Important" ${notice.priority === 'Important' ? 'selected' : ''}>Important</option>
            <option value="Urgent" ${notice.priority === 'Urgent' ? 'selected' : ''}>Urgent</option>
          </select>
        </div>
        
        <div class="f-field" style="margin-bottom:12px">
          <label>Message</label>
          <textarea id="edit-notice-message" style="min-height:120px" required>${notice.message}</textarea>
        </div>
        
        <div style="display:flex;gap:8px;margin-top:20px;justify-content:flex-end">
          <button type="button" class="btn btn-secondary" onclick="closeModal()">Cancel</button>
          <button type="submit" class="btn btn-primary">Save Changes</button>
        </div>
      </form>
    </div>
  `;

  openModal(formHTML);
}

function saveEditNotice(event, noticeId) {
  event.preventDefault();

  const notice = NOTICES_DATA.find(n => n.id === noticeId);
  if (!notice) {
    showToast('<i class="fas fa-times-circle"></i> Notice not found', 'error');
    return;
  }

  notice.title = document.getElementById('edit-notice-title').value;
  notice.audience = document.getElementById('edit-notice-audience').value;
  notice.priority = document.getElementById('edit-notice-priority').value;
  notice.message = document.getElementById('edit-notice-message').value;

  closeModal();
  showToast('<i class="fas fa-check-circle"></i> Notice updated successfully!', 'success');

  setTimeout(() => {
    renderMain();
  }, 1500);
}

function deleteNotice(noticeId) {
  const notice = NOTICES_DATA.find(n => n.id === noticeId);
  if (!notice) {
    showToast('<i class="fas fa-times-circle"></i> Notice not found', 'error');
    return;
  }

  if (confirm(`Are you sure you want to delete "${notice.title}"? This action cannot be undone.`)) {
    NOTICES_DATA.splice(NOTICES_DATA.indexOf(notice), 1);
    showToast('<i class="fas fa-check-circle"></i> Notice deleted successfully!', 'success');

    setTimeout(() => {
      renderMain();
    }, 1500);
  }
}

// MESSAGING MODULE
function messagingModule() {
  // Route to role-specific messaging interface
  if (currentRole === 'Student') return studentMessagingModule();
  if (currentRole === 'Parent') return parentMessagingModule();
  if (currentRole === 'Teacher') return teacherMessagingModule();
  if (currentRole === 'Admin') return adminMessagingModule();

  // Default fallback
  return defaultMessagingModule();
}

